try {
  const raw = $input.first().json.output || $input.first().json.text || "";
  let c = raw.replace(/```json\s*/gi, "").replace(/```\s*/g, "").trim();
  const s = c.indexOf("{"), e = c.lastIndexOf("}");

  if (s === -1 || e === -1) {
    // Falls die KI Klartext statt JSON antwortet, fangen wir das hier ab:
    return [{ json: { 
      confidence_score: 0.0, 
      chain_of_thought: c, 
      events: [], 
      error: true, 
      reason: c.substring(0, 250) // Speichert die Erklärung der KI
    } }];
  }

  const p = JSON.parse(c.substring(s, e + 1));
  if (!Array.isArray(p.events)) p.events = [];
  if (typeof p.confidence_score !== "number") p.confidence_score = 0.0;

  return [{ json: { ...p, error: false } }];
} catch (err) {
  return [{ json: { 
    confidence_score: 0.0, 
    chain_of_thought: "Fehler beim Verarbeiten", 
    events: [], 
    error: true, 
    reason: "Fehler beim Parsen der KI-Antwort: " + err.message 
  } }];
}

const result = $input.first().json;
return [{ json: {
  chain_of_thought:           result.chain_of_thought,
  confidence_score:           result.confidence_score,
  events:                     result.events,
  error:                      false,
  approved:                   true,
  compliance_rejection_count: 0
}}];

// Liest die echte Begründung aus dem letzten Schleifendurchlauf aus
const lastReason = $('Clean-Compliance').last()?.json?.reason || "Keine kommenden Schiffsabfahrten vorhanden.";
return [{ json: { escalate: true, reason: lastReason } }];

const data = $input.first().json;
return [{ json: {
  order_id:               data.order_id,
  disruption:             data.disruption,
  plan_text:              data.plan_text,
  alternatives:           data.alternatives,
  next_vehicles:          data.next_vehicles,
  action_catalog:         data.action_catalog,
  disruption_description: data.disruption_description,
  search_object_type:     data.search_object_type,
  thing_descriptions:     data.thing_descriptions,
  last_rejection:         data.last_rejection || ""
}}];
